  7	import {
  8	  Dropdown,
  9	  DropdownItem,
 10	  DropdownList,
 11	  MenuToggle,
 12	  MenuToggleElement,
 13	} from '@patternfly/react-core';
 14	import { getDRPolicyResourceObj } from '../../../../hooks';
 15	import { DRPolicyKind } from '../../../../types';
 16	import {
 17	  DRPolicyControlState,
 18	  FailoverAndRelocateState,
 19	  FailoverAndRelocateAction,
 20	  FailoverAndRelocateType,
 21	  DRPolicyType,
 22	  ModalFooterStatus,
 23	} from './reducer';
 24	
 25	const getDRPolicyNames = (drpcState: DRPolicyControlState[]): string[] => [
 26	  ...new Set(
 27	    drpcState.map(
 28	      (currentDrpcState) =>
 29	        currentDrpcState?.drPlacementControl?.spec?.drPolicyRef?.name
 30	    )
 31	  ),
 32	];
 33	
 34	const getDRPolicyList = (
 35	  drpolicyNames: string[],
 36	  drPolicies: DRPolicyKind[]
 37	): DRPolicyKind[] =>
 38	  drPolicies.filter((drPolicy) => drpolicyNames.includes(getName(drPolicy)));
 39	
 40	export const DRPolicySelector: React.FC<DRPolicySelectorProps> = ({
 41	  state,
 42	  dispatch,
 43	}) => {
 44	  const { t } = useCustomTranslation();
 45	  const [drPolicies, drPoliciesLoaded, drPoliciesLoadError] =
 46	    useK8sWatchResource<DRPolicyKind[]>(getDRPolicyResourceObj());
 47	  const memoizedDRPCState = useDeepCompareMemoize(
 48	    state.drPolicyControlState,
 49	    true
 50	  );
 51	  const [isOpen, setOpen] = React.useState(false);
 52	
 53	  const setSelected = (selection: DRPolicyType) => {
 54	    dispatch({
 55	      type: FailoverAndRelocateType.SET_SELECTED_DR_POLICY,
 56	      payload: selection,
 57	    });
 58	  };
 59	
 60	  const drPolicyList = React.useMemo(
 61	    () =>
 62	      drPoliciesLoaded &&
 63	      !drPoliciesLoadError &&
 64	      !!memoizedDRPCState.length &&
 65	      !!drPolicies.length
 66	        ? getDRPolicyList(getDRPolicyNames(memoizedDRPCState), drPolicies)
 67	        : [],
 68	    [memoizedDRPCState, drPolicies, drPoliciesLoaded, drPoliciesLoadError]
 69	  );
 70	
 71	  const dropdownItems = React.useMemo(
 72	    () =>
 73	      drPolicyList.map((drPolicy, index) => (
 74	        <DropdownItem
 75	          data-test={`dr-policy-dropdown-item-${index}`}
 76	          key={getUID(drPolicy)}
 77	          value={getName(drPolicy)}
 78	        >
 79	          {getName(drPolicy)}
 80	        </DropdownItem>
 81	      )),
 82	    [drPolicyList]
 83	  );
 84	
 85	  const onSelect = (
 86	    _event?: React.MouseEvent<Element, MouseEvent>,
 87	    value?: string | number
 88	  ) => {
 89	    const drPolicy: DRPolicyKind = drPolicyList.find(
 90	      (policy) => getName(policy) === value
 91	    );
 92	    setSelected({
 93	      policyName: getName(drPolicy),
 94	      drClusters: drPolicy?.spec?.drClusters,
 95	      schedulingInterval: drPolicy?.spec?.schedulingInterval,
 96	      replicationType: getReplicationType(drPolicy),
 97	    });
 98	    setOpen(false);
 99	  };
100	
101	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
102	    <MenuToggle
103	      ref={toggleRef}
104	      id="drPolicy-selection"
105	      data-test="dr-subs-policy-dropdown-toggle"
106	      className="mco-subs-dr-action-body__dropdown--width"
107	      isDisabled={
108	        !drPolicyList.length ||
109	        state.modalFooterStatus === ModalFooterStatus.FINISHED
110	      }
111	      onClick={() => setOpen((prev) => !prev)}
112	      isExpanded={isOpen}
113	    >
114	      {state.selectedDRPolicy.policyName || t('Select')}
115	    </MenuToggle>
116	  );
117	
118	  return (
119	    <Dropdown
120	      className="mco-subs-dr-action-body__dropdown--width"
121	      onSelect={onSelect}
122	      isOpen={isOpen}
123	      onOpenChange={(open: boolean) => setOpen(open)}
124	      toggle={toggle}
125	    >
126	      <DropdownList>{dropdownItems}</DropdownList>
127	    </Dropdown>
128	  );
129	};
130	
131	type DRPolicySelectorProps = {
132	  state: FailoverAndRelocateState;
133	  dispatch: React.Dispatch<FailoverAndRelocateAction>;
134	};

